def analyze_scores(scores):
    if not scores:
        return {'average_score': 0, 'highest_score': 0, 'lowest_score': 0, 'passed': 0, 'failed': 0}
    total = sum(scores)
    avg = total / len(scores)
    high = max(scores)
    low = min(scores)
    passed_count = sum(1 for s in scores if s >= 60)
    failed_count = len(scores) - passed_count
    return {'average_score': avg, 'highest_score': high, 'lowest_score': low, 'passed': passed_count, 'failed': failed_count}
